	}
	infos, err := svc.ListHarnesses(ctx)
	if err != nil {
		return nil, fmt.Errorf("listing harnesses: %w", err)
	}

	now := time.Now().UTC()
	entries := r.sessionIndexEntries(ctx)
	return harnessStatusesFromInfos(infos, entries, now), nil
}

